import java.util.Arrays;

public class MemoFibSequence {
    private long[] cache;
    private int hits, misses;

    public long fib(int n) {
        if (cache[n] != -1) {
            hits++;
            return cache[n];
        }
        misses++;
        if (n <= 1) return cache[n] = n;
        // TODO: cache[n] = fib(n-1) + fib(n-2); return cache[n];
        return 0;
    }

    public void printSequence(int N) {
        cache = new long[N];
        Arrays.fill(cache, -1);
        hits = 0; misses = 0;
        System.out.print("Fib sequence: ");
        for (int i = 0; i < N; i++) System.out.print(fib(i) + (i<N-1?",":"\n"));
        System.out.println("Cache hits: " + hits + ", misses: " + misses);
    }

    public static void main(String[] args) {
        MemoFibSequence mfs = new MemoFibSequence();
        mfs.printSequence(10);
        mfs.printSequence(15);
    }
}

