public class KnapsackMemo {
    int[][] memo;

    public int knapsack(int[] weights, int[] values, int capacity, int idx) {
        if (idx < 0 || capacity <= 0) return 0;
        if (memo[idx][capacity] != -1) return memo[idx][capacity];

        // Option 1: skip item idx
        int skip = knapsack(weights, values, capacity, idx - 1);

        // Option 2: take item idx (only if it fits)
        int take = 0;
        if (weights[idx] <= capacity) {
            // TODO: take = values[idx] + knapsack(weights, values, capacity - weights[idx], idx - 1)
        }

        // TODO: memo[idx][capacity] = Math.max(skip, take); return it
        return 0;
    }

    public int solve(int[] weights, int[] values, int capacity) {
        int n = weights.length;
        memo = new int[n][capacity + 1];
        for (int[] row : memo) Arrays.fill(row, -1);
        return knapsack(weights, values, capacity, n - 1);
    }

    public static void main(String[] args) {
        KnapsackMemo km = new KnapsackMemo();
        int[] w = {1, 3, 4, 5};
        int[] v = {1, 4, 5, 7};
        System.out.println("Max value (cap=7): " + km.solve(w, v, 7));
        System.out.println("Max value (cap=5): " + km.solve(w, v, 5));

        int[] w2 = {2, 3, 4};
        int[] v2 = {3, 4, 5};
        System.out.println("Max value (cap=5): " + km.solve(w2, v2, 5));
    }
}

